import { describe, expect, it } from "vitest";

import { analyzeProtein, cleanProteinSeq } from "./protein";

/**
 * GOLDEN / GROUND-TRUTH suite for analyzeProtein.
 *
 * NO CIRCULAR TESTS. Every expected number below comes from an INDEPENDENT
 * outside authority, never from our own calculator's output. The authority is
 * Biopython's Bio.SeqUtils.ProtParam.ProteinAnalysis (plus
 * Bio.SeqUtils.molecular_weight and Bio.SeqUtils.IsoelectricPoint), the same
 * engine the ExPASy ProtParam web tool implements. The values are generated by
 * frontend/scripts/gen-protein-golden.py (committed alongside this file) so they
 * are reproducible and auditable: re-run that script in a venv with `biopython`
 * and confirm the constants here still match. This test itself is PURE (no
 * Python, no network) and CI-safe.
 *
 * RECONCILIATION GATE (see the script + the first test below): the dipeptide
 * "AG" has a hand-derivable average MW,
 *     mass(A) + mass(G) - 1*water = 89.0932 + 75.0666 - 18.0153 = 146.1445,
 * which equals Biopython's molecular_weight("AG","protein"). That confirms the
 * MW recipe our port uses before any larger sequence is trusted.
 *
 * TOLERANCE. Because analyzeProtein is a faithful line-by-line port of the
 * Biopython algorithms (verbatim constant tables), the two MUST agree to
 * floating-point precision. MW / instability / GRAVY / aromaticity / aliphatic
 * are asserted within 1e-3 absolute (well under 0.1%). pI is asserted within
 * 0.01 pH (the bisection tolerance is 1e-4, so this is generous slack on the
 * reported 2-decimal value). Extinction coefficients are exact integers. Any
 * case that exceeds tolerance is a PORT BUG, not a tolerance to relax.
 *
 * COVERAGE. Tiny hand-checkable peptides; the Biopython docstring pI anchors
 * PETER (4.53) and INGAR (9.75); extinction edge cases (no aromatics -> 0, Tyr
 * only, Trp only, with/without cystines, odd Cys count); acidic vs basic
 * sequences spanning the pI range; and three real proteins (human insulin A
 * chain, EGFP, bovine serum albumin mature chain).
 */

interface Golden {
  id: string;
  seq: string;
  mw: number;
  pi: number;
  epsReduced: number;
  epsOxidized: number;
  a280Reduced: number;
  a280Oxidized: number;
  /** null where Biopython could not compute it (never happens for these). */
  instability: number | null;
  gravy: number;
  aromaticity: number;
  aliphatic: number;
}

