const TOL_ABS = 1e-3; // MW / instability / GRAVY / aromaticity / aliphatic
const TOL_PI = 0.01; // pH units
const TOL_A280 = 1e-4; // derived ratio, slightly looser rounding

describe("analyzeProtein — Biopython ProtParam parity (faithful port)", () => {
  for (const g of GOLDEN) {
    it(`${g.id} (len ${g.seq.length}) matches Biopython`, () => {
      const r = analyzeProtein(g.seq);
      expect(r, `${g.id}: returned null`).not.toBeNull();
      const a = r!;

      // Length: clean sequence length (no non-standard chars in fixtures).
      expect(a.length, `${g.id}: length`).toBe(g.seq.length);

      // Molecular weight — tight (faithful sum-minus-water recipe).
      expect(
        Math.abs(a.molecularWeight - g.mw),
        `PORT BUG: ${g.id} MW ours=${a.molecularWeight.toFixed(4)} vs Biopython=${g.mw}`,
      ).toBeLessThanOrEqual(TOL_ABS);

      // Isoelectric point — bisection parity.
      expect(
        Math.abs(a.isoelectricPoint - g.pi),
        `PORT BUG: ${g.id} pI ours=${a.isoelectricPoint.toFixed(4)} vs Biopython=${g.pi}`,
      ).toBeLessThanOrEqual(TOL_PI);

      // Extinction coefficients — exact integers.
      expect(a.extinctionReduced, `${g.id} eps reduced`).toBe(g.epsReduced);
      expect(a.extinctionOxidized, `${g.id} eps oxidized`).toBe(g.epsOxidized);

      // A280 of a 1 g/L solution = eps / MW.
      expect(
        Math.abs(a.a280Reduced - g.a280Reduced),
        `${g.id} A280 reduced`,
      ).toBeLessThanOrEqual(TOL_A280);
      expect(
        Math.abs(a.a280Oxidized - g.a280Oxidized),
        `${g.id} A280 oxidized`,
      ).toBeLessThanOrEqual(TOL_A280);

      // Instability index (Guruprasad DIWV).
      if (g.instability !== null) {
        expect(
          Math.abs(a.instabilityIndex - g.instability),
          `PORT BUG: ${g.id} instability ours=${a.instabilityIndex.toFixed(4)} vs Biopython=${g.instability}`,
        ).toBeLessThanOrEqual(TOL_ABS);
      }

      // GRAVY (Kyte-Doolittle).
      expect(
        Math.abs(a.gravy - g.gravy),
        `PORT BUG: ${g.id} GRAVY ours=${a.gravy.toFixed(4)} vs Biopython=${g.gravy}`,
      ).toBeLessThanOrEqual(TOL_ABS);

      // Aromaticity (Lobry).
      expect(
        Math.abs(a.aromaticity - g.aromaticity),
        `${g.id} aromaticity`,
      ).toBeLessThanOrEqual(TOL_ABS);

      // Aliphatic index (Ikai closed form).
      expect(
        Math.abs(a.aliphaticIndex - g.aliphatic),
        `${g.id} aliphatic index`,
      ).toBeLessThanOrEqual(TOL_ABS);
    });
  }
});

describe("analyzeProtein — reconciliation gate + published anchors", () => {
  it("dipeptide AG MW == hand value 146.1445 (== Biopython)", () => {
    // mass(A)=89.0932 + mass(G)=75.0666 - water=18.0153 = 146.1445
    const r = analyzeProtein("AG")!;
    expect(r.molecularWeight).toBeCloseTo(146.1445, 4);
  });

  it("PETER pI == 4.53 (Biopython ProtParam docstring)", () => {
    const r = analyzeProtein("PETER")!;
    expect(r.isoelectricPoint).toBeCloseTo(4.53, 2);
  });

  it("INGAR pI == 9.75 (Biopython IsoelectricPoint docstring)", () => {
    const r = analyzeProtein("INGAR")!;
    expect(r.isoelectricPoint).toBeCloseTo(9.75, 2);
  });
});

describe("analyzeProtein — convention + guards", () => {
  it("returns null when no standard residue is present", () => {
    expect(analyzeProtein("")).toBeNull();
    expect(analyzeProtein("   \n 123 ")).toBeNull();
    expect(analyzeProtein("123 -- *")).toBeNull(); // digits / gaps / stop only
    expect(analyzeProtein("BZXU O")).toBeNull(); // all non-standard residues
  });

  it("ignores whitespace, lowercases, and strips a FASTA header line content", () => {
    // Lowercase + internal whitespace must not change the result.
    const spaced = analyzeProtein("p e t e r");
    const lower = analyzeProtein("peter");
    expect(spaced).not.toBeNull();
    expect(spaced!.molecularWeight).toBeCloseTo(lower!.molecularWeight, 6);
    expect(spaced!.isoelectricPoint).toBeCloseTo(lower!.isoelectricPoint, 6);
  });

  it("flags non-standard / ambiguous residues and excludes them from the math", () => {
    const { clean, nonStandard } = cleanProteinSeq("ACXBZU*OJ-DE");
    expect(clean).toBe("ACDE");
    // X B Z U O J * are all flagged; gap/punctuation are silently dropped.
    expect(nonStandard).toEqual(["*", "B", "J", "O", "U", "X", "Z"]);
    const r = analyzeProtein("ACXBZU*OJ-DE")!;
    expect(r.length).toBe(4);
    expect(r.nonStandardChars).toContain("X");
  });

  it("extinction coefficient is zero when there are no Trp/Tyr/Cys", () => {
    const r = analyzeProtein("AGGAGGAGGAGG")!;
    expect(r.extinctionReduced).toBe(0);
    expect(r.extinctionOxidized).toBe(0);
    expect(r.a280Reduced).toBe(0);
  });

  it("composition counts sum to length and percentages to ~100", () => {
    const r = analyzeProtein("INGAR")!;
    const totalCount = r.composition.reduce((s, c) => s + c.count, 0);
    expect(totalCount).toBe(r.length);
    const totalPct = r.composition.reduce((s, c) => s + c.percent, 0);
    expect(totalPct).toBeCloseTo(100, 6);
  });
});
